        this.$ = $;
    }
    in(def) {
        return new InternalChainedMatchParser(this.$, def === undefined ? undefined : this.$.parse(def));
    }
    at(key, cases) {
        return new InternalChainedMatchParser(this.$).at(key, cases);
    }
    case(when, then) {
        return new InternalChainedMatchParser(this.$).case(when, then);
    }
}
