    }
    caseEntries(entries) {
        for (let i = 0; i < entries.length; i++) {
            const [k, v] = entries[i];
            if (k === "default") {
                if (i !== entries.length - 1) {
                    throwParseError(`default may only be specified as the last key of a switch definition`);
                }
                return this.default(v);
            }
            if (typeof v !== "function") {
